def _params_from_state() -> "P.Parameters":
    updates = {c["key"]: state[c["key"]] for c in control_specs()
               if state[c["key"]] is not None}
    return P.Parameters(**updates)


def _manual_transform_matrix() -> list[list[float]] | None:
    """Compose the operator nudge (rotations then translation) into a 4x4 list.

    Returns ``None`` when the nudge is disabled or effectively identity so the
    backend takes its untouched auto-registration path.
    """
    if not state.manual_enabled:
        return None
    tx, ty, tz = float(state.manual_tx), float(state.manual_ty), float(state.manual_tz)
    rx, ry, rz = (np.deg2rad(float(state.manual_rx)),
                  np.deg2rad(float(state.manual_ry)),
                  np.deg2rad(float(state.manual_rz)))
    if not any((tx, ty, tz, rx, ry, rz)):
        return None

    def _rot(axis: str, a: float) -> np.ndarray:
        c, s = np.cos(a), np.sin(a)
        R = np.eye(4)
        if axis == "x":
            R[1, 1], R[1, 2], R[2, 1], R[2, 2] = c, -s, s, c
        elif axis == "y":
            R[0, 0], R[0, 2], R[2, 0], R[2, 2] = c, s, -s, c
        else:  # z
            R[0, 0], R[0, 1], R[1, 0], R[1, 1] = c, -s, s, c
        return R

    M = _rot("z", rz) @ _rot("y", ry) @ _rot("x", rx)
    M[0, 3], M[1, 3], M[2, 3] = tx, ty, tz
    return M.tolist()


# --------------------------------------------------------------------------- #
# Stats / meta rendering (HTML, no overlap: simple definition rows).
# --------------------------------------------------------------------------- #
def _stat_rows(title: str, items: list[tuple[str, str]]) -> str:
    rows = "".join(
        f"<div style='display:flex;justify-content:space-between;gap:12px;"
        f"padding:1px 0;font-size:12px;line-height:1.5'>"
        f"<span style='color:#555'>{k}</span>"
        f"<span style='font-variant-numeric:tabular-nums;font-weight:600'>{v}</span></div>"
        for k, v in items
    )
    return (f"<div style='margin-bottom:8px'>"
            f"<div style='font-size:11px;font-weight:700;letter-spacing:.04em;"
            f"text-transform:uppercase;color:#333;margin-bottom:2px'>{title}</div>"
            f"{rows}</div>")


def _meta_html() -> str:
    m = SESSION.get("meta") or {}
    if not m:
        return "<div style='font-size:12px;color:#888'>No scan loaded.</div>"
    if SESSION.get("is_mesh"):
        items = [
            ("Kind", "Surface mesh"),
            ("Format", str(m.get("format", "—"))),
            ("Points", f"{m.get('n_points', 0):,}"),
        ]
        return _stat_rows("Loaded mesh", items)
    items = [
        ("Series", str(m.get("series", "—"))),
        ("Shape (z,y,x)", "×".join(str(s) for s in m.get("shape", []))),
        ("Spacing (mm)", "×".join(str(s) for s in m.get("spacing_mm", []))),
        ("Laterality", str(m.get("laterality", "—"))),
    ]
    return _stat_rows("Loaded scan", items)


# --------------------------------------------------------------------------- #
# Hover picking: read the scalar at the point under the cursor.
# --------------------------------------------------------------------------- #
def _on_hover(point, *_a, **_k):
    """pyvista hover callback: show the picked scalar + position in a tooltip.

    ``point`` is the world-space (x,y,z) under the cursor (or None off-surface).
    We look up the active surface's scalar there and compare it to the map mean.
    """
    key = "deviation_mm" if (state.mode == "B" and state.b_view == "deviation") \
        else "thickness_mm"
    mesh = _LAST_MESH["deviation"] if key == "deviation_mm" else _LAST_MESH["thickness"]
    if point is None or mesh is None or key not in mesh.point_data:
        with state:
            state.hover_active = False
        state.flush()
        return
    try:
        pid = mesh.find_closest_point(np.asarray(point, dtype=float))
        val = float(mesh.point_data[key][pid])
        pos = np.asarray(mesh.points[pid], dtype=float)
        scal = np.asarray(mesh.point_data[key], dtype=float)
        mean = float(np.mean(scal))
    except Exception:  # noqa: BLE001
        return
    unit = "mm"
    label = "Deviation" if key == "deviation_mm" else "Thickness"
    fmt = "%+.2f" if key == "deviation_mm" else "%.2f"
    delta = val - mean
    html_out = (
        f"<div style='font-weight:700;font-size:13px;margin-bottom:2px'>"
        f"{label}: {fmt % val} {unit}</div>"
        f"<div style='font-size:11px;color:#ddd;line-height:1.5'>"
        f"vs map mean {fmt % mean} ({'+' if delta >= 0 else ''}{delta:.2f} {unit})<br>"
        f"x {pos[0]:.1f} · y {pos[1]:.1f} · z {pos[2]:.1f} mm</div>"
    )
    with state:
        state.hover_html = html_out
        state.hover_active = True
    state.flush()


def _enable_hover() -> None:
    """(Re)attach the hover-picking callback to the current plotter surface."""
    try:
        PLOTTER.disable_picking()
    except Exception:  # noqa: BLE001
        pass
    try:
        PLOTTER.enable_point_picking(
            callback=_on_hover, show_message=False, show_point=False,
            use_picker="hardware", left_clicking=False, picker="point",
        )
    except Exception:  # noqa: BLE001
        # Hover picking is best-effort; the rest of the UI works without it.
        pass


# --------------------------------------------------------------------------- #
# Compute (runs on a background thread).
# --------------------------------------------------------------------------- #
def _compute_worker():
    try:
        params = _params_from_state()
        with _LOCK:
            sides = dict(SESSION["sides"])
            is_mesh_sess = bool(SESSION["is_mesh"])
        if not sides:
            raise RuntimeError("No scan loaded.")

        mode = state.mode
        wants_thickness = mode == "A" or (mode == "B" and state.b_view == "thickness")

        if wants_thickness:
            if is_mesh_sess:
                raise RuntimeError(
                    "This is a surface mesh — thickness needs a volume. "
                    "Use Mode B deviation instead.")
            side_key = state.side
            side = sides.get(side_key)
            if side is None:
                raise RuntimeError(f"Unknown side '{side_key}'.")
            res = pipeline.analyze_thickness(
                side["arr"], side["spacing"], params,
                region_label=None, offset_xyz=side["offset_xyz"],
            )
            _LAST_MESH["thickness"] = res["mesh"]
            build_thickness_scene(PLOTTER, res["mesh"], params=params,
                                  side_label=_side_label(side_key))
            s = res["stats"]
            html_out = _meta_html() + _stat_rows(
                f"Thickness — {_side_label(side_key)} (mm)",
                [("mean", f"{s['mean']:.3f}"), ("median", f"{s['median']:.3f}"),
                 ("sd", f"{s['sd']:.3f}"), ("min", f"{s['min']:.3f}"),
                 ("max", f"{s['max']:.3f}"), ("n vertices", f"{s['n']:,}")],
            ) + _stat_rows("Segmentation",
                           [("region label", str(res["region_label"])),
                            ("metal fraction", f"{res['metal_fraction']:.4f}")])
        else:  # Mode B deviation
            ref = sides.get(state.ref_side)
            tgt = sides.get(state.tgt_side)
            if ref is None or tgt is None:
                raise RuntimeError("Reference/target side unknown.")
            if state.ref_side == state.tgt_side:
                raise RuntimeError("Choose two different sides for deviation.")
            manual = _manual_transform_matrix()
            res = pipeline.compare_sides(ref, tgt, params, manual_transform=manual)
            _LAST_MESH["deviation"] = res["mesh"]
            build_deviation_scene(PLOTTER, res["mesh"], params=params)
            st = res["stats"]
            reg = res["registration"]
            html_out = _meta_html() + _stat_rows(
                "Registration",
                [("RMS (mm)", f"{reg['rms']:.3f}"),
                 ("inlier fraction", f"{reg['inlier_fraction']:.3f}"),
                 ("manual nudge", "yes" if reg.get("manual_adjusted") else "no"),
                 ("reference", _side_label(state.ref_side)),
                 ("target", _side_label(state.tgt_side))],
            ) + _stat_rows(
                "Signed deviation (mm)",
                [("mean", f"{st['mean']:.3f}"), ("median", f"{st['median']:.3f}"),
                 ("sd", f"{st['sd']:.3f}"),
                 ("max +", f"{st['max_positive']:.3f}"),
                 ("max −", f"{st['max_negative']:.3f}"),
                 ("added vol (cc)", f"{st['added_volume_cc']:.2f}"),
                 ("removed vol (cc)", f"{st['removed_volume_cc']:.2f}")],
            )

        _enable_hover()
        with state:
            state.stats_html = html_out
            state.status = "done"
            state.status_msg = "Recompute complete."
        if ctrl.view_update:
            ctrl.view_update()
        state.flush()
    except Exception as e:  # noqa: BLE001
        traceback.print_exc()
        with state:
            state.status = "error"
            state.status_msg = f"Compute failed: {e}"
        state.flush()


def _side_label(name: str) -> str:
    return {"left": "Left", "right": "Right", "full": "Full",
            "mesh": "Mesh"}.get(name, name.capitalize())


def recompute(*_a, **_k):
    """Kick off a background recompute with the CURRENT params/mode/side."""
    if state.status == "computing":
        return
    with state:
        state.status = "computing"
        state.status_msg = ("Computing… (Mode B deviation involves registration "
                            "and can take a while)" if (state.mode == "B" and
                            state.b_view == "deviation") else "Computing…")
    state.flush()
    threading.Thread(target=_compute_worker, daemon=True).start()


ctrl.recompute = recompute


# --------------------------------------------------------------------------- #
# Export: build a multi-format bundle via core.export.export_bundle and expose
# each result as a real download link served from /downloads.
# --------------------------------------------------------------------------- #
def _camera_from_state() -> dict:
    return {
        "azimuth": float(state.cam_azimuth),
        "elevation": float(state.cam_elevation),
        "roll": float(state.cam_roll),
        "zoom": float(state.cam_zoom),
    }


def _export_worker():
    try:
        params = _params_from_state()
        with _LOCK:
            sides = dict(SESSION["sides"])
            is_mesh_sess = bool(SESSION["is_mesh"])
        formats = list(state.export_formats or [])
        if not formats:
            raise RuntimeError("Pick at least one export format.")
        dpi = int(state.export_dpi)
        if dpi <= 0:
            raise RuntimeError("DPI must be positive.")

        mode = state.mode
        diverging = mode == "B" and state.b_view == "deviation"
        if diverging:
            ref = sides.get(state.ref_side)
            tgt = sides.get(state.tgt_side)
            if ref is None or tgt is None or state.ref_side == state.tgt_side:
                raise RuntimeError("Mode B export needs two distinct sides.")
            res = pipeline.compare_sides(ref, tgt, params,
                                         manual_transform=_manual_transform_matrix())
            mesh, scalar = res["mesh"], res["scalar"]
        else:
            if is_mesh_sess:
                raise RuntimeError(
                    "Thickness export needs a volume; this is a surface mesh.")
            side = sides.get(state.side)
            if side is None:
                raise RuntimeError(f"Unknown side '{state.side}'.")
            res = pipeline.analyze_thickness(side["arr"], side["spacing"], params,
                                             offset_xyz=side["offset_xyz"])
            mesh, scalar = res["mesh"], "thickness_mm"

        key = uuid.uuid4().hex[:12]
        out_dir = EXPORTS_DIR / key
        files = export_bundle(mesh, scalar, params, out_dir,
                              formats=tuple(f.lower() for f in formats),
                              dpi=dpi, camera=_camera_from_state(),
                              diverging=diverging, stem="export")
        links = [{"fmt": fmt, "url": f"/downloads/{key}/{Path(p).name}"}
                 for fmt, p in files.items()]
        with state:
            state.export_links = links
            state.export_busy = False
            state.export_msg = f"Exported {len(links)} file(s)."
        state.flush()
    except Exception as e:  # noqa: BLE001
        traceback.print_exc()
        with state:
            state.export_busy = False
            state.export_msg = f"Export failed: {e}"
            state.export_links = []
        state.flush()


def do_export(*_a, **_k):
    if state.export_busy:
        return
    with state:
        state.export_busy = True
        state.export_msg = "Exporting…"
        state.export_links = []
    state.flush()
    threading.Thread(target=_export_worker, daemon=True).start()


ctrl.do_export = do_export


# --------------------------------------------------------------------------- #
# Share / switcher actions.
# --------------------------------------------------------------------------- #
def refresh_config(*_a, **_k):
    cfg = read_public_config()
    with state:
        state.cfg_public = cfg["public"]
        state.cfg_trame_url = cfg["trame_url"] or ""
        state.cfg_react_url = cfg["react_url"] or ""
        state.share_url = cfg["trame_url"] or FALLBACK_TRAME_URL
        state.other_ui_url = cfg["react_url"] or FALLBACK_REACT_URL
    state.flush()


ctrl.refresh_config = refresh_config


# --------------------------------------------------------------------------- #
# File upload: VFileInput yields a list of {name, content(bytes/base64), size}.
# Accepts every supported format; branches mesh vs volume, single vs bilateral.
# --------------------------------------------------------------------------- #
@state.change("upload_file")
def _on_upload(upload_file, **_k):
    if not upload_file:
        return
    entry = upload_file[0] if isinstance(upload_file, list) else upload_file
    name = entry.get("name", "upload.zip")
    content = entry.get("content")
    if content is None:
        return
    if isinstance(content, str):  # base64 fallback
        import base64
        content = base64.b64decode(content.split(",")[-1])
    dest = WORKDIR / f"upload_{uuid.uuid4().hex[:8]}_{name}"
    dest.parent.mkdir(parents=True, exist_ok=True)
    dest.write_bytes(bytes(content))

    with state:
        state.status = "computing"
        state.status_msg = f"Ingesting {name}…"
    state.flush()

    def _job():
        try:
            _load_source(dest)
            with state:
                _refresh_session_ui()
                if SESSION.get("is_mesh"):
                    state.status_msg = ("Surface mesh loaded — Mode B "
                                        "(comparison / viewing) only.")
                elif state.is_bilateral:
                    state.status_msg = "Bilateral scan loaded (Left / Right)."
                else:
                    state.status_msg = "Single-sided scan loaded (Full)."
                state.status = "idle"
            state.flush()
            recompute()
        except Exception as e:  # noqa: BLE001
            traceback.print_exc()
            with state:
                state.status = "error"
                state.status_msg = f"Upload ingest failed: {e}"
            state.flush()

    threading.Thread(target=_job, daemon=True).start()


# --------------------------------------------------------------------------- #
# UI: registry-driven control renderer.
# --------------------------------------------------------------------------- #
def _render_control(spec: dict):
    key, label = spec["key"], spec["label"]
    unit = f" ({spec['unit']})" if spec.get("unit") else ""
    if spec["control"] == "bool":
        v3.VSwitch(v_model=(key,), label=label, density="compact",
                   hide_details=True, color="primary")
    elif spec["control"] == "enum":
        state[f"{key}_choices"] = spec.get("choices") or []
        v3.VSelect(v_model=(key,), items=(f"{key}_choices",),
                   label=label, density="compact", hide_details=True,
                   variant="outlined")
    else:  # int / float slider
        v3.VSlider(v_model=(key,), label=f"{label}{unit}",
                   min=spec.get("minimum", 0), max=spec.get("maximum", 1),
                   step=spec.get("step", 1), thumb_label=True,
                   density="compact", hide_details=True, color="primary")


