# --------------------------------------------------------------------------- #
# Startup: load the demo scan (server-side) and do an initial Mode A compute.
# --------------------------------------------------------------------------- #
def _bootstrap():
    refresh_config()
    if DEMO_ZIP is None:
        with state:
            state.status = "error"
            state.status_msg = ("No demo dataset found. Build one with "
                                "scripts/make_demo.py, or upload a scan.")
        state.flush()
        return
    try:
        _load_source(DEMO_ZIP, layout="bilateral")
        with state:
            _refresh_session_ui()
            state.status_msg = "Demo scan loaded. Hit Apply / Recompute."
        state.flush()
        recompute()
    except Exception as e:  # noqa: BLE001
        traceback.print_exc()
        with state:
            state.status = "error"
            state.status_msg = f"Startup load failed: {e}"
        state.flush()


if __name__ == "__main__":
    _bootstrap()
    server.start(port=8081)
